INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-6f0ba476-moex-00045', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '李君為經常居住於中華民國境內的國民，90年與甲女結婚，未約定夫妻財產制度。李君於114年 過世，死亡時遺留的財產總額為3,500萬元，均為婚後財產，另有房屋貸款700萬元。甲女財產 為2,500萬元（其中包括結婚前財產800萬元，以及李君死亡前1年贈與200萬元）。請依現行適 用規定計算配偶剩餘財產差額分配請求權扣除額為多少？', '["750萬元", "650萬元", "550萬元", "0元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00046', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '張先生於106年5月購買房地作為自住房屋，並於該處辦竣戶籍登記，持有至114年期間均未出 租或供營業使用。114年6月出售該房地，交易所得淨額為700萬元。依房地合一新制規定，下 列何者錯誤？', '["設籍、持有及實際居住6年為同等條件，其中任一未符合，仍得享有400萬元免稅額", "因持有並設籍自住已滿6年，可適用自住房地400萬元免稅額，超過部分按10%稅率課徵", "若僅持有與實際居住滿6年，但設籍期間未滿6年，則不得適用400萬元免稅額", "個人、配偶或未成年子女於交易日前 6年內已適用過自住房地 400萬元免稅額者，不得再次 適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00047', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '張小姐於114年持有新竹縣都市計畫區內一筆土地，面積500平方公尺，公告地價為每平方公尺 20,000元。該土地供自住使用，並符合自用住宅用地條件。新竹縣114年度累進起點地價為100 萬元，且張小姐未申報地價。請問其114年度應納地價稅為多少？', '["55,000元", "67,000元", "87,500元", "129,500元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00048', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '李君於112年3月18日簽約出售土地售價1,200萬元，移轉現值為670萬元，按一般稅率核課並 繳納土地增值稅45萬元，112年5月12日完成移轉登記。114年3月18日簽約購置自用住宅土 地，114年5月20日申報土地增值稅，移轉現值690萬元，核定土地增值稅53萬元，可申請退 回土地增值稅多少元？', '["45萬元", "原出售土地非按自用稅率核課，無法申請退稅", "未在2年內重購土地，無法申請退稅", "65萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00049', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '關於土地增值稅自用住宅用地優惠稅率之規定，下列何者正確？', '["出售自用住宅用地前1年內曾出租者，只要其他條件仍符合，即使出租使用，也可以申請優惠 稅率", "若申報土地增值稅時，漏未申請自用住宅用地優惠稅率者，不得補申請，必須用一般稅率課徵", "優惠稅率一生一次制度不可被例外解除，即使已過持有年限或符合一生一屋等新條件者，亦不 得再次申請優惠", "優惠稅率適用之都市土地面積上限為3公畝，非都市土地為7公畝；超過部分，其超過部分須 依一般稅率累進徵收"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00050', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '甲以其房屋與乙之股票交換，下列何者正確？', '["課徵交換契稅，甲為納稅義務人", "課徵交換契稅，乙為納稅義務人", "課徵買賣契稅，甲為納稅義務人", "課徵買賣契稅，乙為納稅義務人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00051', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依所得稅法規定，夫妻選擇各類所得分開計稅時，下列何者可於個人部分扣除？①免稅額  ②薪', '["一般扣除額", "財產交易損失扣除額  ⑤儲蓄投資特別扣除額", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00052', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '甲公司欠繳營業稅500萬元，稅捐稽徵機關依法移送強制執行。查該公司在繳納期間內已解散， 但其清算人未盡清算責任，依現行稅捐稽徵法規定，下列何者正確？', '["稅捐債務隨公司解散歸於消滅", "清算人應於分配剩餘財產前依稅捐受償順序繳清稅捐；若未履行，對未清之稅捐負繳納義務", "僅公司原負責人於任期內負責未清稅捐", "若股東按持股比例分配剩餘財產，即由股東承擔全部所分配部分之稅捐責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00053', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依所得稅法施行細則規定，有關申報義務、核課程序及不可抗力事由之處理，下列何者錯誤？', '["營利事業應向其登記地之稽徵機關辦理申報；若總機構設於境外但在我國境內設有固定營業場 所者，仍應依規定在我國辦理申報", "稽徵機關查得個人綜合所得總額超過免稅額與標準扣除額合計數而未辦理結算申報者，應依施 行細則第58條規定逕予核課", "依施行細則第 10 條之 1 規定，納稅義務人因不可抗力事故致不能依限繳納稅捐者，得申請延 期或分期繳納", "不可抗力事故僅限於風災、水災、地震等自然災害，不包括疫情、瘟疫或戰爭等其他情形"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00054', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '甲因投資失利，財務狀況不佳，積欠A屋房貸遭法拍，拍定價為1,280萬元，其他資訊如下：', '["該屋土地增值稅80萬元", "契稅5萬元", "銀行抵押貸款880萬元", "強制執行費用13萬元 ⑤該屋欠繳房屋稅3萬元  ⑥欠繳房屋稅之滯納金及罰鍰9,800元。依稅捐稽徵法規定之清償順 序為何？"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
